import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import { CAR_PHOTOS } from '../data';

export default function LeafletMap({ cars, onCarClick, selectedCarId }) {
  const mapRef = useRef(null);
  const mapInstance = useRef(null);
  const markers = useRef([]);

  useEffect(() => {
    if (mapInstance.current) return;

    const map = L.map(mapRef.current, { zoomControl: false }).setView([53.9006, 27.559], 12);

    // Тёмная тема карты
    L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
      attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OSM</a> &copy; <a href="https://carto.com/">CARTO</a>',
      maxZoom: 19,
    }).addTo(map);

    L.control.zoom({ position: 'topright' }).addTo(map);
    mapInstance.current = map;

    // Маркеры
    cars.forEach(car => {
      const color = car.available ? '#3b82f6' : '#ef4444';
      const icon = L.divIcon({
        className: 'lf-marker',
        html: `<div style="width:38px;height:38px;border-radius:50%;background:${color};border:3px solid white;display:flex;align-items:center;justify-content:center;box-shadow:0 2px 14px ${color}80;font-size:11px;font-weight:700;color:white;font-family:'Outfit',sans-serif;cursor:pointer;">${car.price}</div>`,
        iconSize: [38, 38],
        iconAnchor: [19, 19],
      });

      const marker = L.marker([car.lat, car.lng], { icon }).addTo(map);

      const popup = `
        <div style="font-family:'Outfit',sans-serif;min-width:210px;padding:2px;">
          <img src="${CAR_PHOTOS[car.id]?.[0]}" style="width:100%;height:110px;object-fit:cover;border-radius:8px;margin-bottom:8px;" />
          <div style="font-size:16px;font-weight:700;margin-bottom:2px;">${car.name}</div>
          <div style="font-size:12px;color:#8b8da0;margin-bottom:6px;">${car.year} · ${car.transmission} · ${car.fuel}</div>
          <div style="font-size:12px;color:#8b8da0;margin-bottom:8px;">📍 ${car.address}</div>
          <div style="display:flex;justify-content:space-between;align-items:center;">
            <span style="font-size:18px;font-weight:800;color:#3b82f6;">${car.price} BYN<span style="font-size:11px;color:#8b8da0;"> / сутки</span></span>
            <span style="font-size:12px;color:${car.available ? '#10b981' : '#ef4444'};font-weight:700;">
              ${car.available ? '✓ Доступен' : '✗ Занят'}
            </span>
          </div>
        </div>
      `;
      marker.bindPopup(popup, { className: 'dark-popup', maxWidth: 280 });
      marker.on('click', () => onCarClick && onCarClick(car));
      markers.current.push({ carId: car.id, marker });
    });

    return () => {
      map.remove();
      mapInstance.current = null;
      markers.current = [];
    };
  }, [cars]);

  useEffect(() => {
    if (!selectedCarId || !mapInstance.current) return;
    const found = markers.current.find(m => m.carId === selectedCarId);
    const car = cars.find(c => c.id === selectedCarId);
    if (found && car) {
      mapInstance.current.flyTo([car.lat, car.lng], 15, { duration: 1 });
      setTimeout(() => found.marker.openPopup(), 600);
    }
  }, [selectedCarId, cars]);

  return <div ref={mapRef} style={{ width: '100%', height: '100%', borderRadius: 20 }} />;
}
